INSERT INTO `chat_message` VALUES (5, '0eae5460-db18-4426-abc7-fb85af02768c', 'user', 'This game how to start?', '2026-03-20 17:18:21.860');
INSERT INTO `chat_message` VALUES (6, '0eae5460-db18-4426-abc7-fb85af02768c', 'assistant', 'It seems the document search tool is not working properly. However, I can provide you with general information about how to start playing League of Legends based on standard knowledge.\n\nTo start playing League of Legends:\n\n1. **Download and Install**: Visit the official League of Legends website and download the game client for your operating system (Windows or macOS).\n\n2. **Create an Account**: Sign up for a free account on the Riot Games website.\n\n3. **Install the Game**: Run the installer and follow the setup instructions.\n\n4. **Complete Tutorial**: When you first launch the game, you\'ll be guided through a tutorial that teaches you the basics of gameplay, controls, and objectives.\n\n5. **Practice Mode**: Before jumping into real matches, try the Practice Tool where you can play against AI bots to get comfortable with champions and mechanics.\n\n6. **Learn the Basics**: Understand core concepts like last-hitting minions, map awareness, objective control (like Dragon and Baron Nashor), and team coordination.\n\n7. **Start with Easy Modes**: Begin with Normal games (against other players) before moving to Ranked matches.\n\nWould you like me to elaborate on any specific aspect of getting started, such as character selection, basic controls, or game modes?', '2026-03-20 17:18:21.869');
