DROP TABLE IF EXISTS `graph_thread`;
CREATE TABLE `graph_thread`  (
  `thread_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `thread_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `is_released` tinyint(1) NOT NULL DEFAULT 0,
  PRIMARY KEY (`thread_id`) USING BTREE,
  UNIQUE INDEX `IDX_GRAPH_THREAD_NAME_RELEASED`(`thread_name` ASC, `is_released` ASC) USING BTREE
