-- ----------------------------
-- Table structure for knowledge_docs
-- ----------------------------
DROP TABLE IF EXISTS `knowledge_docs`;
CREATE TABLE `knowledge_docs`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '文档ID',
  `game_id` bigint NOT NULL COMMENT '游戏ID',
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件名',
  `file_name_origin` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '原始文件名',
  `file_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件类型（pdf/txt/docx等）',
  `file_size` bigint NOT NULL COMMENT '文件大小(byte)',
  `file_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件存储URL',
  `chunk_count` int NOT NULL DEFAULT 0 COMMENT '文档分片数量',
  `uploaded_by` bigint UNSIGNED NOT NULL COMMENT '上传人ID（关联users表）',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '上传时间',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间（逻辑删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_game_id`(`game_id` ASC) USING BTREE COMMENT '游戏ID索引',
  INDEX `fk_kd_uploader`(`uploaded_by` ASC) USING BTREE,
  CONSTRAINT `fk_kd_uploader` FOREIGN KEY (`uploaded_by`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '游戏知识库文档表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of knowledge_docs
-- ----------------------------

-- ----------------------------
-- Table structure for qa_records
-- ----------------------------
DROP TABLE IF EXISTS `qa_records`;
CREATE TABLE `qa_records`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '问答记录ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID（关联users表）',
  `game_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '游戏ID',
  `question` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '问题内容',
  `answer` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '回答内容',
  `is_favorite` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否收藏：0-否 1-是',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间（逻辑删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_game`(`user_id` ASC, `game_id` ASC) USING BTREE COMMENT '用户+游戏索引',
  INDEX `idx_user_created`(`user_id` ASC, `created_time` ASC) USING BTREE COMMENT '用户+创建时间索引',
  CONSTRAINT `fk_qa_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户问答记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of qa_records
-- ----------------------------

-- ----------------------------
-- Table structure for users
-- ----------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '用户ID，主键',
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户名，唯一标识',
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码哈希值',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '角色：管理员/普通用户',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间（逻辑删除，NULL=未删除）',
  `updated_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_username`(`username` ASC) USING BTREE COMMENT '用户名唯一索引'
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户信息表' ROW_FORMAT = Dynamic;

